#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

#define MAX_SIZE 100

typedef struct {
 int data[MAX_SIZE];
 int size;
} MinHeap;

// Initialize an empty heap
void initHeap(MinHeap *h) {
 h->size = 0;
}

// Check if heap is empty
int isEmpty(MinHeap *h) {
 return h->size == 0;
}

// Check if heap is full
int isFull(MinHeap *h) {
 return h->size >= MAX_SIZE;
}

// Get parent index
int parent(int i) {
 return (i - 1) / 2;
}

// Get left child index
int leftChild(int i) {
 return 2 * i + 1;
}

// Get right child index
int rightChild(int i) {
 return 2 * i + 2;
}

// Swap two elements
void swap(int *a, int *b) {
 int temp = *a;
 *a = *b;
 *b = temp;
}

/*
 * Insert operation: Percolate Up (Bubble Up)
 * Time Complexity: O(log n)
 */
void insert(MinHeap *h, int key) {
 if (isFull(h)) {
 printf("Heap overflow! Cannot insert %d\n", key);
 return;
 }

 // Place new element at the end
 int i = h->size;
 h->data[i] = key;
 h->size++;

 // Percolate up: fix heap property
 while (i > 0) {
 int parentIdx = parent(i);
 if (h->data[i] < h->data[parentIdx]) {
 swap(&h->data[i], &h->data[parentIdx]);
 i = parentIdx;
 } else {
 break;
 }
 }
 printf("Inserted %d into heap\n", key);
}

/*
 * Find minimum element (at root)
 * Time Complexity: O(1)
 */
int findMin(MinHeap *h) {
 if (isEmpty(h)) {
 printf("Heap is empty!\n");
 return INT_MIN;
 }
 return h->data[0]; // Root contains minimum
}

/*
 * DeleteMin operation: Percolate Down (Bubble Down)
 * Time Complexity: O(log n)
 */
int deleteMin(MinHeap *h) {
 if (isEmpty(h)) {
 printf("Heap underflow! Cannot delete.\n");
 return INT_MIN;
 }

 // Store minimum (root)
 int min = h->data[0];

 // Replace root with last element
 h->data[0] = h->data[h->size - 1];
 h->size--;

 // Percolate down: fix heap property
 int i = 0;
 while (1) {
 int left = leftChild(i);
 int right = rightChild(i);
 int smallest = i;

 // Find smallest among parent and children
 if (left < h->size && h->data[left] < h->data[smallest]) {
 smallest = left;
 }
 if (right < h->size && h->data[right] < h->data[smallest]) {
 smallest = right;
 }

 // Swap and continue if heap property violated
 if (smallest != i) {
 swap(&h->data[i], &h->data[smallest]);
 i = smallest;
 } else {
 break;
 }
 }

 return min;
}

// Display heap contents
void display(MinHeap *h) {
 printf("Heap array: [");
 for (int i = 0; i < h->size; i++) {
 printf("%d", h->data[i]);
 if (i < h->size - 1) printf(", ");
 }
 printf("]\n");
 printf("Size: %d\n", h->size);
}

// Main function demonstrating heap operations
int main() {
 MinHeap heap;
 initHeap(&heap);

 printf("=== Inserting elements into Min-Heap ===\n");
 int elements[] = {15, 10, 20, 8, 25, 5, 30};
 int n = sizeof(elements) / sizeof(elements[0]);

 for (int i = 0; i < n; i++) {
 insert(&heap, elements[i]);
 }

 display(&heap);

 printf("\n=== FindMin: %d ===\n", findMin(&heap));

 printf("\n=== DeleteMin operations ===\n");
 for (int i = 0; i < 3; i++) {
 int min = deleteMin(&heap);
 printf("Deleted Min: %d\n", min);
 }

 display(&heap);

 return 0;
}
